61: /**
62:  * <p>This class centralizes all security properties and common security
63:  * methods. One of its primary uses is to manage providers.
64:  *
65:  * <p>The default values of security properties are read from an
66:  * implementation-specific location, which is typically the properties file
67:  * {@code conf/security/java.security} in the Java installation directory.
68:  *
69:  * @implNote If the properties file fails to load, the JDK implementation will
70:  * throw an unspecified error when initializing the {@code Security} class.
71:  *
72:  * @author Benjamin Renaud
73:  * @since 1.1
74:  */
75: 
76: public final class Security {
77: 
78:     /* Are we debugging? -- for developers */
79:     private static final Debug sdebug =
80:                         Debug.getInstance("properties");
81: 
82:     /* The java.security properties */
83:     private static final Properties props = new Properties() {
84:         @Override
85:         public synchronized Object put(Object key, Object val) {
86:             if (key instanceof String strKey && val instanceof String strVal &&
87:                     SecPropLoader.isInclude(strKey)) {
88:                 SecPropLoader.loadInclude(strVal);
89:                 return null;
90:             }
91:             return super.put(key, val);
92:         }
93:     };
94: 
95:     /* cache a copy for recording purposes */
96:     private static Properties initialSecurityProperties;
97: 
98:     // An element in the cache
99:     private static class ProviderProperty {
100:         String className;
101:         Provider provider;
102:     }
103: 
104:     private static final class SecPropLoader {
105:         private enum LoadingMode {OVERRIDE, APPEND}
106: 
107:         private static final String OVERRIDE_SEC_PROP =
108:                 "security.overridePropertiesFile";
109: 
110:         private static final String EXTRA_SYS_PROP =
111:                 "java.security.properties";
112: 
113:         private static Path currentPath;
114: 
115:         private static final Set<Path> activePaths = new HashSet<>();
116: 
117:         static void loadAll() {
118:             // first load the master properties file to
119:             // determine the value of OVERRIDE_SEC_PROP
120:             loadMaster();
121:             loadExtra();
122:         }
123: 
124:         static boolean isInclude(String key) {
125:             return "include".equals(key);
126:         }
127: 
128:         static void checkReservedKey(String key)
129:                 throws IllegalArgumentException {
130:             if (isInclude(key)) {
131:                 throw new IllegalArgumentException("Key '" + key +
132:                         "' is reserved and cannot be used as a " +
133:                         "Security property name.");
134:             }
135:         }
