274:      *         are deemed invalid for constructing the {@code Cipher} object
275:      */
276:     protected Cipher(CipherSpi cipherSpi,
277:                      Provider provider,
278:                      String transformation) {
279:         // See bug 4341369 & 4334690 for more info.
280:         // If the caller is trusted, then okay.
281:         // Otherwise throw an IllegalArgumentException.
282:         if (!JceSecurityManager.INSTANCE.isCallerTrusted(
283:                 JceSecurityManager.WALKER.getCallerClass(), provider)) {
284:             throw new IllegalArgumentException("Cannot construct cipher");
285:         }
286:         this.spi = cipherSpi;
287:         this.provider = provider;
288:         this.transformation = transformation;
289:         this.cryptoPerm = CryptoAllPermission.INSTANCE;
290:         this.lock = null;
