306:     private Cipher(CipherSpi firstSpi, Service firstService,
307:             Iterator<Service> serviceIterator, String transformation,
308:             List<Transform> transforms) {
309:         this.firstSpi = firstSpi;
310:         this.firstService = firstService;
311:         this.serviceIterator = serviceIterator;
312:         this.transforms = transforms;
