317:     private static final String SHA512TRUNCATED = "SHA512/2";
318: 
319:     private static String[] tokenizeTransformation(String transformation)
320:             throws NoSuchAlgorithmException {
321:         if (transformation == null) {
322:             throw new NoSuchAlgorithmException("No transformation given");
323:         }
324:         /*
325:          * array containing the components of a cipher transformation:
326:          *
327:          * index 0: algorithm component (e.g., AES)
328:          * index 1: feedback component (e.g., CFB)
329:          * index 2: padding component (e.g., PKCS5Padding)
330:          */
331:         String[] parts = { "", "", "" };
332: 
333:         // check if the transformation contains algorithms with "/" in their
334:         // name which can cause the parsing logic to go wrong
335:         int sha512Idx = transformation.toUpperCase(Locale.ENGLISH)
336:                 .indexOf(SHA512TRUNCATED);
337:         int startIdx = (sha512Idx == -1 ? 0 :
338:                 sha512Idx + SHA512TRUNCATED.length());
339:         int endIdx = transformation.indexOf('/', startIdx);
340:         if (endIdx == -1) {
341:             // algorithm
342:             parts[0] = transformation.trim();
343:         } else {
344:             // algorithm/mode/padding
345:             parts[0] = transformation.substring(0, endIdx).trim();
346:             startIdx = endIdx+1;
347:             endIdx = transformation.indexOf('/', startIdx);
348:             if (endIdx == -1) {
349:                 throw new NoSuchAlgorithmException("Invalid transformation"
350:                             + " format:" + transformation);
351:             }
352:             parts[1] = transformation.substring(startIdx, endIdx).trim();
353:             parts[2] = transformation.substring(endIdx+1).trim();
354:         }
355:         if (parts[0].isEmpty()) {
356:             throw new NoSuchAlgorithmException("Invalid transformation: " +
357:                                    "algorithm not specified-"
358:                                    + transformation);
359:         }
360:         return parts;
361:     }
362: 
363:     // Provider attribute name for supported chaining mode
364:     private static final String ATTR_MODE = "SupportedModes";
365:     // Provider attribute name for supported padding names
366:     private static final String ATTR_PAD  = "SupportedPaddings";
367: 
368:     // constants indicating whether the provider supports
369:     // a given mode or padding
370:     private static final int S_NO    = 0;       // does not support
371:     private static final int S_MAYBE = 1;       // unable to determine
372:     private static final int S_YES   = 2;       // does support
373: 
374:     /**
375:      * Nested class to deal with modes and paddings.
376:      */
377:     private static class Transform {
378:         // transform string to lookup in the provider
379:         final String transform;
380:         // the mode/padding suffix in upper case. for example, if the algorithm
381:         // to lookup is "AES/CBC/PKCS5Padding" suffix is "/CBC/PKCS5PADDING"
382:         // if lookup is "AES", suffix is the empty string
383:         // needed because aliases prevent straight transform.equals()
384:         final String suffix;
385:         // value to pass to setMode() or null if no such call required
386:         final String mode;
387:         // value to pass to setPadding() or null if no such call required
388:         final String pad;
389:         Transform(String alg, String suffix, String mode, String pad) {
390:             this.transform = alg + suffix;
391:             this.suffix = suffix.toUpperCase(Locale.ENGLISH);
392:             this.mode = mode;
393:             this.pad = pad;
394:         }
395:         // set mode and padding for the given SPI
396:         void setModePadding(CipherSpi spi) throws NoSuchAlgorithmException,
397:                 NoSuchPaddingException {
398:             if (mode != null) {
399:                 spi.engineSetMode(mode);
400:             }
401:             if (pad != null) {
402:                 spi.engineSetPadding(pad);
403:             }
404:         }
405:         // check whether the given services supports the mode and
406:         // padding described by this Transform
407:         int supportsModePadding(Service s) {
408:             int smode = supportsMode(s);
409:             if (smode == S_NO) {
410:                 return smode;
411:             }
412:             int spad = supportsPadding(s);
413:             // our constants are defined so that Math.min() is a tri-valued AND
414:             return Math.min(smode, spad);
415:         }
416: 
417:         // separate methods for mode and padding
418:         // called directly by cipher only to throw the correct exception
419:         int supportsMode(Service s) {
420:             return supports(s, ATTR_MODE, mode);
421:         }
422:         int supportsPadding(Service s) {
423:             return supports(s, ATTR_PAD, pad);
424:         }
425: 
426:         private static int supports(Service s, String attrName, String value) {
427:             if (value == null) {
428:                 return S_YES;
429:             }
430:             String regexp = s.getAttribute(attrName);
431:             if (regexp == null) {
432:                 return S_MAYBE;
433:             }
434:             return matches(regexp, value) ? S_YES : S_NO;
435:         }
436: 
437:         // ConcurrentMap<String,Pattern> for previously compiled patterns
438:         private static final ConcurrentMap<String, Pattern> patternCache =
439:             new ConcurrentHashMap<String, Pattern>();
440: 
441:         private static boolean matches(String regexp, String str) {
442:             Pattern pattern = patternCache.get(regexp);
443:             if (pattern == null) {
444:                 pattern = Pattern.compile(regexp);
445:                 patternCache.putIfAbsent(regexp, pattern);
446:             }
447:             return pattern.matcher(str.toUpperCase(Locale.ENGLISH)).matches();
448:         }
